CREATE DATABASE IF NOT EXISTS imec_site CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE imec_site;

CREATE TABLE users (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,email VARCHAR(160) NOT NULL UNIQUE,password_hash VARCHAR(255) NOT NULL,role ENUM('admin') NOT NULL DEFAULT 'admin',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE company_settings (id INT PRIMARY KEY DEFAULT 1,company_name VARCHAR(160) NOT NULL DEFAULT 'IMEC Metalúrgica',logo_url VARCHAR(255),phone VARCHAR(60),whatsapp VARCHAR(60),email VARCHAR(160),address VARCHAR(255),city VARCHAR(120),state VARCHAR(80),hero_image_url VARCHAR(255),youtube_url VARCHAR(255),instagram_url VARCHAR(255),linkedin_url VARCHAR(255),facebook_url VARCHAR(255),updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE pages (id INT AUTO_INCREMENT PRIMARY KEY,slug VARCHAR(80) NOT NULL UNIQUE,title VARCHAR(180) NOT NULL,subtitle TEXT,content LONGTEXT,image_url VARCHAR(255),is_active TINYINT(1) NOT NULL DEFAULT 1,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE services (id INT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(160) NOT NULL,slug VARCHAR(180) NOT NULL UNIQUE,short_description TEXT,description LONGTEXT,icon VARCHAR(80),image_url VARCHAR(255),display_order INT NOT NULL DEFAULT 0,is_active TINYINT(1) NOT NULL DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE portfolio_projects (id INT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(180) NOT NULL,slug VARCHAR(200) NOT NULL UNIQUE,category VARCHAR(120),location VARCHAR(160),year VARCHAR(20),short_description TEXT,description LONGTEXT,cover_image_url VARCHAR(255),display_order INT NOT NULL DEFAULT 0,is_active TINYINT(1) NOT NULL DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE gallery_categories (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(140) NOT NULL,slug VARCHAR(160) NOT NULL UNIQUE,display_order INT NOT NULL DEFAULT 0,is_active TINYINT(1) NOT NULL DEFAULT 1);
CREATE TABLE gallery_photos (id INT AUTO_INCREMENT PRIMARY KEY,category_id INT,title VARCHAR(180) NOT NULL,image_url VARCHAR(255) NOT NULL,alt_text VARCHAR(220),display_order INT NOT NULL DEFAULT 0,is_active TINYINT(1) NOT NULL DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY (category_id) REFERENCES gallery_categories(id) ON DELETE SET NULL);
CREATE TABLE videos (id INT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(180) NOT NULL,youtube_url VARCHAR(255) NOT NULL,description TEXT,display_order INT NOT NULL DEFAULT 0,is_active TINYINT(1) NOT NULL DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE quote_requests (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(160) NOT NULL,company VARCHAR(160),email VARCHAR(160) NOT NULL,phone VARCHAR(80) NOT NULL,service_interest VARCHAR(160),message TEXT NOT NULL,status ENUM('novo','em_contato','finalizado') NOT NULL DEFAULT 'novo',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);

INSERT INTO company_settings (id,company_name,phone,whatsapp,email,address,city,state,hero_image_url) VALUES (1,'IMEC Metalúrgica','(18) 3786-1272','551837861272','comercial@imecmetalurgica.com.br','Rua Júlio Ventura, 655','Sud Mennucci','São Paulo','') ON DUPLICATE KEY UPDATE company_name=VALUES(company_name),phone=VALUES(phone),whatsapp=VALUES(whatsapp),email=VALUES(email),address=VALUES(address),city=VALUES(city),state=VALUES(state);
INSERT INTO pages (slug,title,subtitle,content) VALUES ('home','Soluções completas para projetos e equipamentos industriais','Equipamentos e serviços para fabricação de etanol, açúcar e energia. Referência nacional em mais de 100 usinas de açúcar e álcool e na indústria alimentícia.','A IMEC oferece aos seus clientes soluções completas para projetos e equipamentos para fabricação de etanol, açúcar e energia.'),('quem-somos','Desde 1998 atendendo o setor sucroalcooleiro','Sediada em Sud Mennucci-SP, a IMEC atua com fabricação, montagem e manutenção de equipamentos para etanol, açúcar e energia.','A IMEC surgiu da união dos diretores Edson Ribeiro e José Della Possa, ambos com extensa experiência no setor sucroalcooleiro. A empresa iniciou suas atividades fabricando, montando e mantendo colunas de destilação, pré-evaporadores, tanques, trocadores de calor e outros equipamentos industriais.'),('produtos','Equipamentos e soluções para o setor sucroalcooleiro','Concentrador de levedura, decantador de fuligem, colunas de destilação, pré-evaporadores, tanques, trocadores de calor e plantas industriais.','Produtos e equipamentos para usinas, processos de destilação, secagem de leveduras, tratamento de fuligem e plantas industriais.'),('setores','Mercados atendidos pela IMEC','Usinas de açúcar e álcool, etanol, energia, plantas industriais e indústria alimentícia.','Atuação voltada ao setor sucroalcooleiro, energia, plantas industriais e indústria alimentícia.'),('clientes','Experiência com mais de 100 usinas','A IMEC construiu sua trajetória atendendo usinas de açúcar e álcool e empresas da indústria alimentícia.','Relacionamento técnico, comunicação direta e acompanhamento de performance após a entrega.'),('trabalhe-conosco','Envie seu currículo para a IMEC','Banco de talentos para futuras oportunidades.','A IMEC valoriza o tempo e dedicação de seus colaboradores e mantém banco de currículos.'),('orcamento','Solicite uma cotação','Conte sua demanda para montagem industrial, suporte técnico, manutenção, projetos ou equipamentos para usinas.','Atendemos demandas de usinas de açúcar e álcool, energia e indústria alimentícia.') ON DUPLICATE KEY UPDATE title=VALUES(title),subtitle=VALUES(subtitle),content=VALUES(content);
INSERT INTO services (title,slug,short_description,description,icon,display_order) VALUES ('Montagem Industrial','montagem-industrial','Montagem de equipamentos, plantas e conjuntos para usinas de etanol, açúcar e energia.','Execução de montagem industrial com planejamento de campo para o setor sucroalcooleiro.','Factory',1),('Suporte Técnico','suporte-tecnico','Acompanhamento técnico antes, durante e depois da entrega dos projetos e equipamentos.','Suporte especializado para performance, eficiência e qualidade dos produtos e serviços prestados.','Wrench',2),('Manutenção de Equipamentos','manutencao-equipamentos','Manutenção e reforma de colunas, pré-evaporadores, tanques e trocadores de calor.','Serviços de manutenção para equipamentos industriais do setor sucroalcooleiro.','Settings',3),('Projetos','projetos','Soluções completas para fabricação, montagem e melhoria de processos industriais.','Projetos para equipamentos, plantas e sistemas ligados à fabricação de etanol, açúcar e energia.','Building2',4),('Locação de Guinchos e Munks','locacao-guinchos-munks','Apoio para movimentação e montagem de equipamentos industriais em campo.','Locação e suporte operacional para içamento e movimentação de cargas.','HardHat',5),('Equipamentos para Usinas','equipamentos-usinas','Produtos e serviços para fabricação de etanol, açúcar, energia e indústria alimentícia.','Soluções para usinas e processos industriais, incluindo colunas de destilação, tanques e sistemas de tratamento.','Gauge',6) ON DUPLICATE KEY UPDATE title=VALUES(title),short_description=VALUES(short_description),description=VALUES(description),icon=VALUES(icon),display_order=VALUES(display_order);
INSERT INTO portfolio_projects (title,slug,category,short_description,description,display_order) VALUES ('Concentrador de Levedura','concentrador-levedura','Conder Therm','Tecnologia de película pulverizada ou autolimpante para secagem de leveduras.','Produto disponibilizado ao mercado sucroalcooleiro em parceria com a Spraying Systems do Brasil.',1),('Decantador de Fuligem','decantador-fuligem','Tratamento de fuligem','Sistema completo de tratamento de fuligem de caldeira.','Solução para tratamento de fuligem em processos de caldeira.',2),('Colunas de Destilação','colunas-destilacao','Etanol','Colunas para etanol combustível, etanol neutro e etanol especial.','Equipamentos e serviços especializados para destilação no setor sucroalcooleiro.',3),('Pré-evaporadores e Tanques','pre-evaporadores-tanques','Equipamentos industriais','Fabricação, montagem e manutenção de pré-evaporadores e tanques.','Equipamentos industriais presentes na história da IMEC desde o início das atividades.',4),('Trocadores de Calor','trocadores-calor','Equipamentos industriais','Fabricação e manutenção de trocadores de calor.','Soluções para processos industriais de usinas e indústria alimentícia.',5),('Plantas para Usinas','plantas-usinas','Etanol, açúcar e energia','Soluções completas para projetos e equipamentos de usinas.','Atuação em plantas e equipamentos para fabricação de etanol, açúcar e energia.',6) ON DUPLICATE KEY UPDATE title=VALUES(title),category=VALUES(category),short_description=VALUES(short_description),description=VALUES(description),display_order=VALUES(display_order);
INSERT INTO gallery_categories (name,slug,display_order) VALUES ('Montagem Industrial','montagem-industrial',1),('Equipamentos para Usinas','equipamentos-usinas',2),('Manutenção de Equipamentos','manutencao-equipamentos',3),('Projetos','projetos',4) ON DUPLICATE KEY UPDATE name=VALUES(name),display_order=VALUES(display_order);
